mapper.select:
SELECT id, warehouse_id, code, name, type, remark, status, deleted, created_at, updated_at, created_by, updated_by FROM zone WHERE deleted = 0
AND (name LIKE CONCAT('%', #{keyword}, '%') OR code LIKE CONCAT('%', #{keyword}, '%'))
AND warehouse_id = #{warehouseId}
AND status = #{status}
ORDER BY warehouse_id ASC, code ASC, id ASC
